				if w.LastResult.ResultRev != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "Result rev: %s\n", w.LastResult.ResultRev[:12])
				}
			}
			if w.LastError != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Error:     %s\n", w.LastError)
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&asJSON, "json", false, "Output as JSON")

	return cmd
