// are not retained.
type PhaseTransition struct {
	Phase    string    `json:"phase"`
	TS       time.Time `json:"ts"`
	PhaseSeq int       `json:"phase_seq"`
}

// LastAttemptInfo summarises the most recently completed attempt.
