)

// resolveTsnetAuthKey applies auth key precedence:
// TS_AUTHKEY env var > --tsnet-auth-key CLI flag > config file auth_key.
// The env var is preferred because CLI flags are visible in ps/history.
func resolveTsnetAuthKey(envKey, flagKey, configKey string) string {
	if envKey != "" {
		return envKey
	}
	if flagKey != "" {
		return flagKey
	}
	return configKey
}

func (f *CommandFactory) newServerCommand() *cobra.Command {
	var port int
	var addr string
	var tlsCert string
	var tlsKey string
	var tsnetEnabled bool
	var tsnetHostname string
	var tsnetAuthKey string

	cmd := &cobra.Command{
		Use:   "server",
		Short: "Start the DDx HTTP and MCP server",
		Long: `Start the DDx server exposing documents, beads, document graph,
and agent session logs over HTTP REST and MCP endpoints.

HTTP API:
  GET /api/health              Liveness check
  GET /api/ready               Readiness check with dependency status
  GET /api/documents           List library documents (?type=)
  GET /api/documents/:path     Read a document
  GET /api/search?q=           Full-text search across documents
  GET /api/personas/:role      Resolve persona for a role
  GET /api/beads               List beads (?status=&label=)
  GET /api/beads/:id           Show a specific bead
  GET /api/beads/ready         List ready beads
  GET /api/beads/blocked       List blocked beads
  GET /api/beads/status        Bead summary counts
  GET /api/beads/dep/tree/:id  Dependency tree for a bead
  GET /api/docs/graph          Document dependency graph
  GET /api/docs/stale          Stale documents
  GET /api/docs/:id            Document metadata and staleness
  GET /api/docs/:id/deps       Upstream dependencies
  GET /api/docs/:id/dependents Downstream dependents
  GET /api/agent/sessions      List agent sessions (?harness=&since=)
  GET /api/agent/sessions/:id  Session detail
  GET /api/metrics/summary     Process metrics summary (?since=)
  GET /api/metrics/cost        Process metrics cost (?bead=&feature=&since=)
  GET /api/metrics/cycle-time  Process metrics cycle time (?since=)
  GET /api/metrics/rework      Process metrics rework (?since=)

MCP (POST /mcp):
  ddx_list_documents           List library documents
  ddx_read_document            Read a document
  ddx_search                   Full-text search
  ddx_resolve_persona          Resolve persona for a role
  ddx_list_beads               List beads
  ddx_show_bead                Show a specific bead
  ddx_bead_ready               List ready beads
  ddx_bead_status              Bead summary counts
  ddx_doc_graph                Document dependency graph
  ddx_doc_stale                Stale documents
  ddx_doc_show                 Document metadata
  ddx_doc_deps                 Upstream dependencies
  ddx_agent_sessions           List agent sessions`,
		Aliases: []string{"serve"},
		RunE: func(cmd *cobra.Command, args []string) error {
			listenAddr := fmt.Sprintf("%s:%d", addr, port)
			fmt.Fprintf(cmd.OutOrStdout(), "DDx server listening on https://%s\n", listenAddr)
			srv := server.New(listenAddr, f.WorkingDir)

			// Build tsnet config: flags override config file
			tc := &config.TsnetConfig{}
			if cfg, err := config.LoadWithWorkingDir(f.WorkingDir); err == nil && cfg.Server != nil && cfg.Server.Tsnet != nil {
				*tc = *cfg.Server.Tsnet
			}
			if tsnetEnabled {
				tc.Enabled = true
			}
			if tsnetHostname != "" {
				tc.Hostname = tsnetHostname
			}
			// Prefer TS_AUTHKEY env var; CLI flag is a fallback (secrets on CLI are visible in ps/history)
			tc.AuthKey = resolveTsnetAuthKey(os.Getenv("TS_AUTHKEY"), tsnetAuthKey, tc.AuthKey)
			if tc.Enabled {
				srv.TsnetConfig = tc
				fmt.Fprintf(cmd.OutOrStdout(), "DDx ts-net enabled (hostname: %s)\n", func() string {
					if tc.Hostname != "" {
						return tc.Hostname
					}
					return "ddx"
				}())
			}

			return srv.ListenAndServeTLS(tlsCert, tlsKey)
		},
	}

	cmd.Flags().IntVarP(&port, "port", "p", 7743, "Port to listen on")
	cmd.Flags().StringVar(&addr, "addr", "127.0.0.1", "Address to bind to")
	cmd.Flags().StringVar(&tlsCert, "tls-cert", "", "TLS certificate file (PEM); auto-generates self-signed cert if omitted")
	cmd.Flags().StringVar(&tlsKey, "tls-key", "", "TLS private key file (PEM); auto-generates self-signed key if omitted")
	cmd.Flags().BoolVar(&tsnetEnabled, "tsnet", false, "Enable Tailscale ts-net listener (opt-in, see ADR-006)")
	cmd.Flags().StringVar(&tsnetHostname, "tsnet-hostname", "", "Tailscale hostname (default: ddx)")
	cmd.Flags().StringVar(&tsnetAuthKey, "tsnet-auth-key", "", "Tailscale auth key for headless/CI use (SECURITY: visible in ps/history; prefer TS_AUTHKEY env var)")

	// Worker management
	cmd.AddCommand(f.newServerWorkersCommand())

	// Service management
	cmd.AddCommand(f.newServerInstallServiceCommand())
	cmd.AddCommand(f.newServerServiceStatusCommand())
	cmd.AddCommand(f.newServerUninstallServiceCommand())

	return cmd
}

package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
	"time"

	"github.com/spf13/cobra"
)

func (f *CommandFactory) newServerWorkersCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "workers",
		Short: "Manage agent execution workers",
	}

	cmd.AddCommand(f.newServerWorkersListCommand())
	cmd.AddCommand(f.newServerWorkersShowCommand())
	cmd.AddCommand(f.newServerWorkersLogCommand())

	return cmd
}

func (f *CommandFactory) newServerWorkersListCommand() *cobra.Command {
	var asJSON bool

	cmd := &cobra.Command{
		Use:   "list",
		Short: "List agent execution workers",
		RunE: func(cmd *cobra.Command, args []string) error {
			base := resolveServerURL(f.WorkingDir)

			resp, err := newLocalServerClient().Get(base + "/api/agent/workers")
			if err != nil {
				return fmt.Errorf("server request: %w", err)
			}
			defer func() { _ = resp.Body.Close() }()

			body, err := io.ReadAll(resp.Body)
			if err != nil {
				return fmt.Errorf("reading response: %w", err)
			}

			if asJSON {
				fmt.Fprintln(cmd.OutOrStdout(), string(body))
				return nil
			}

			var workers []workerRecord
			if err := json.Unmarshal(body, &workers); err != nil {
				return fmt.Errorf("parsing response: %w", err)
			}

			if len(workers) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No workers.")
				return nil
			}

			for _, w := range workers {
				state := w.State
				if state == "exited" {
					if w.LastResult.Status != "" {
						state = w.LastResult.Status
					}
				}
				model := w.Model
				if model == "" && w.LastResult.Model != "" {
					model = w.LastResult.Model
				}
				bead := w.LastResult.BeadID
				if bead == "" {
					bead = "-"
				}
				age := formatDuration(time.Since(w.StartedAt))
				fmt.Fprintf(cmd.OutOrStdout(), "%-36s %-6s %-18s %-24s %s\n",
					w.ID, age, state, model, bead)
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&asJSON, "json", false, "Output as JSON")

	return cmd
}

func (f *CommandFactory) newServerWorkersShowCommand() *cobra.Command {
	var asJSON bool

	cmd := &cobra.Command{
		Use:   "show <worker-id>",
		Short: "Show worker details",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			base := resolveServerURL(f.WorkingDir)

			resp, err := newLocalServerClient().Get(base + "/api/agent/workers/" + args[0])
			if err != nil {
				return fmt.Errorf("server request: %w", err)
			}
			defer func() { _ = resp.Body.Close() }()

			body, err := io.ReadAll(resp.Body)
			if err != nil {
				return fmt.Errorf("reading response: %w", err)
			}

			if asJSON {
				fmt.Fprintln(cmd.OutOrStdout(), string(body))
				return nil
			}

			var w workerRecord
			if err := json.Unmarshal(body, &w); err != nil {
				return fmt.Errorf("parsing response: %w", err)
			}

			state := w.State
			if state == "exited" && w.LastResult.Status != "" {
				state = w.LastResult.Status
			}
			model := w.Model
			if model == "" && w.LastResult.Model != "" {
				model = w.LastResult.Model
			}

			fmt.Fprintf(cmd.OutOrStdout(), "Worker:    %s\n", w.ID)
			fmt.Fprintf(cmd.OutOrStdout(), "State:     %s\n", state)
			fmt.Fprintf(cmd.OutOrStdout(), "Model:     %s\n", model)
			fmt.Fprintf(cmd.OutOrStdout(), "Harness:   %s\n", w.Harness)
			fmt.Fprintf(cmd.OutOrStdout(), "Started:   %s (%s ago)\n", w.StartedAt.Format(time.RFC3339), formatDuration(time.Since(w.StartedAt)))
			if !w.ExitedAt.IsZero() {
				fmt.Fprintf(cmd.OutOrStdout(), "Exited:    %s (ran %s)\n", w.ExitedAt.Format(time.RFC3339), formatDuration(w.ExitedAt.Sub(w.StartedAt)))
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Project:   %s\n", w.ProjectRoot)
			if w.Once {
				fmt.Fprintf(cmd.OutOrStdout(), "Mode:      once\n")
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Attempts:  %d  Success: %d  Failed: %d\n", w.Attempts, w.Successes, w.Failures)
			if w.LastResult.BeadID != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Last bead: %s\n", w.LastResult.BeadID)
				fmt.Fprintf(cmd.OutOrStdout(), "Last status: %s\n", w.LastResult.Status)
				if w.LastResult.Detail != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "Last detail: %s\n", w.LastResult.Detail)
				}
				if w.LastResult.BaseRev != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "Base rev:  %s\n", w.LastResult.BaseRev[:12])
				}
				if w.LastResult.ResultRev != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "Result rev: %s\n", w.LastResult.ResultRev[:12])
				}
			}
			if w.LastError != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Error:     %s\n", w.LastError)
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&asJSON, "json", false, "Output as JSON")

	return cmd
}

func (f *CommandFactory) newServerWorkersLogCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "log <worker-id>",
		Short: "View worker progress and session log",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			base := resolveServerURL(f.WorkingDir)

			resp, err := newLocalServerClient().Get(base + "/api/agent/workers/" + args[0] + "/log")
			if err != nil {
				return fmt.Errorf("server request: %w", err)
			}
			defer func() { _ = resp.Body.Close() }()

			body, err := io.ReadAll(resp.Body)
			if err != nil {
				return fmt.Errorf("reading response: %w", err)
			}

			var logResp struct {
				Stdout string `json:"stdout"`
				Stderr string `json:"stderr"`
			}
			if err := json.Unmarshal(body, &logResp); err != nil {
				return fmt.Errorf("parsing response: %w", err)
			}

			if logResp.Stdout != "" {
				fmt.Fprint(cmd.OutOrStdout(), logResp.Stdout)
			}
			if logResp.Stderr != "" {
				fmt.Fprint(os.Stderr, logResp.Stderr)
			}
			return nil
		},
	}

	return cmd
}

