	if ref != "" {
		gitArgs = []string{"diff", ref, "--", doc.Path}
	} else {
		gitArgs = []string{"diff", "--", doc.Path}
	}

	diffCmd := exec.Command("git", gitArgs...)
	diffCmd.Dir = s.WorkingDir
	diffCmd.Env = scrubbedGitEnv()
	out, gitErr := diffCmd.Output()
