func (s *Server) handleCreateBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	var req struct {
		Title       string   `json:"title"`
		Type        string   `json:"type"`
		Priority    *int     `json:"priority"`
		Labels      []string `json:"labels"`
		Description string   `json:"description"`
		Acceptance  string   `json:"acceptance"`
		Parent      string   `json:"parent"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body"})
		return
	}
	if req.Title == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "title is required"})
		return
	}

	store := s.beadStore()
	b := &bead.Bead{
		Title:       req.Title,
		IssueType:   req.Type,
		Labels:      req.Labels,
		Description: req.Description,
		Acceptance:  req.Acceptance,
		Parent:      req.Parent,
	}
	if req.Priority != nil {
		b.Priority = *req.Priority
	}
	if err := store.Create(b); err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusCreated, b)
}

func (s *Server) handleUpdateBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	id := r.PathValue("id")
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id is required"})
		return
	}

	var req struct {
		Status      *string  `json:"status"`
		Labels      []string `json:"labels"`
		Description *string  `json:"description"`
		Acceptance  *string  `json:"acceptance"`
		Priority    *int     `json:"priority"`
		Notes       *string  `json:"notes"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body"})
		return
	}

	store := s.beadStore()
	err := store.Update(id, func(b *bead.Bead) {
		if req.Status != nil {
			b.Status = *req.Status
		}
		if req.Labels != nil {
			b.Labels = req.Labels
		}
		if req.Description != nil {
			b.Description = *req.Description
		}
		if req.Acceptance != nil {
			b.Acceptance = *req.Acceptance
		}
		if req.Priority != nil {
			b.Priority = *req.Priority
		}
		if req.Notes != nil {
			b.Notes = *req.Notes
		}
	})
	if err != nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": err.Error()})
		return
	}

	updated, err := store.Get(id)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusOK, updated)
}

func (s *Server) handleClaimBead(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "write endpoints are localhost-only"})
		return
	}
	id := r.PathValue("id")
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id is required"})
		return
	}

	var req struct {
		Assignee string `json:"assignee"`
		Session  string `json:"session"`
		Worktree string `json:"worktree"`
	}
	_ = json.NewDecoder(r.Body).Decode(&req)

	store := s.beadStore()
	if err := store.ClaimWithOptions(id, req.Assignee, req.Session, req.Worktree); err != nil {
